    base:desc "Steering angle sensor measuring vehicle steering position"
    DTDFVocab:producedData VehicleSteeringTelemetryReceived
]

// Data Transmitted
instance LiDARPointCloudDataReceived : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HokuyoUST10LXLidar
]

instance DepthCameraFrameReceived : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom IntelD435iDepthCamera
]

instance VehicleSpeedTelemetryReceived : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TachometerSpeedSensor
]

instance VehicleSteeringTelemetryReceived : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringAngleSensor
]

// Data transmitted via the cluster enabler
instance ClusteredPointCloudDataTransmitted : DTDFVocab:DataTransmitted [
    /* No properties needed */
]

// Data
instance LiDARPointCloudReceived : DTDFVocab:Data [
    base:desc "Raw LiDAR point cloud data streamed at ~10Hz"
    DTDFVocab:inputTo LiDARClusteringEnabler
    DTDFVocab:fromData LiDARPointCloudDataReceived
]

instance DepthCameraFrameData : DTDFVocab:Data [
    base:desc "RGB‑D frames from Intel D435i captured at the vehicle's sensor rate"
    DTDFVocab:inputTo VisualizationEnabler
    DTDFVocab:fromData DepthCameraFrameReceived
]

instance VehicleSpeedData : DTDFVocab:Data [
    base:desc "Vehicle speed telemetry data transmitted by the tachometer"
    DTDFVocab:inputTo DataMonitoringEnabler
    DTDFVocab:fromData VehicleSpeedTelemetryReceived
]

instance VehicleSteeringData : DTDFVocab:Data [
    base:desc "Vehicle steering telemetry data transmitted by the steering angle sensor"
    DTDFVocab:inputTo DataMonitoringEnabler
    DTDFVocab:fromData VehicleSteeringTelemetryReceived
]

instance ClusteredPointCloudData : DTDFVocab:Data [
    base:desc "Clustered LiDAR point clouds produced by DBSCAN"
